const pineconeNode = {
  name: 'Pinecone Retriever',
  type: 'n8n-nodes-base.pinecone',
  parameters: {
    operation: 'query',
    indexName: 'rag-docs',
    queryEmbedding: '={{ $json.query }}',
    topK: 5,
    includeMetadata: true,
    namespace: 'production'
  }
};

const aiAgentNode = {
  name: 'RAG Synthesizer',
  type: 'n8n-nodes-langchain.agent',
  parameters: {
    agent: 'openai-functions',
    model: 'gpt-4',
    tools: ['retrievalTool'],
    systemPrompt: `You are a RAG assistant. Always cite sources using [source_id] format.
Verify all facts against provided context. Never hallucinate.`
  }
};

const contextItems = $input.all();
const assembledContext = contextItems.map(item => {
  return `SOURCE [${item.json.metadata.source_id}]:
${item.json.text}\n---`;
}).join('\n');

return {
  context: assembledContext,
  query: $json.query,
  sources: contextItems.map(i => i.json.metadata)
};

const response = $json.response;
const citationRegex = /\[(\d+)\]/g;
const citations = [];
let match;

while ((match = citationRegex.exec(response)) !== null) {
  citations.push(parseInt(match[1]));
}

return {
  response,
  extractedCitations: citations,
  sourceCount: citations.length
};

