const vexWebhookNode = {
  name: 'Vex Guardrails',
  type: 'n8n-nodes-base.httpRequest',
  parameters: {
    method: 'POST',
    url: 'https://api.vex.dev/v1/verify',
    headers: {
      Authorization: 'Bearer {{ $secrets.vex_api_key }}',
      'Content-Type': 'application/json'
    },
    body: {
      input: '={{ $json.response }}',
      context: '={{ $json.context }}',
      sources: '={{ $json.sources }}',
      checks: ['source_faithfulness', 'hallucination', 'context_relevance', 'citation_accuracy']
    }
  }
};

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

const result = await vex.verify({
  input: $json.response,
  context: $json.context,
  framework: 'n8n-rag',
  checks: {
    sourceFaithfulness: { threshold: 0.9 },
    hallucination: { threshold: 0.1 },
    contextRelevance: { threshold: 0.8 },
    citationAccuracy: { threshold: 0.95 }
  }
});

if (!result.pass) {
  throw new Error(`Vex failed: ${JSON.stringify(result.issues)}`);
}

return { verified: true, score: result.score };

const vexResult = $json;

if (!vexResult.verified) {
  return {
    response: "I'm sorry, I cannot provide an accurate response with the available sources. Please try rephrasing your query or contact support.",
    status: 'blocked',
    issues: vexResult.issues,
    score: vexResult.score
  };
}

// Pass verified response downstream
return {
  response: $json.original_response,
  citations: $json.citations,
  verified: true
};
